module RefModule(clk, rst, en, count);

	// I/O declarations
	input clk, rst, en;
	output reg [3:0] count;

	// Counter logic
	  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
		if (rst) begin
			count <= 4'b0000;
		end else if (en) begin
			count <= count + 1;
		end
	end

endmodule
